if is_spc_block_verified_precompile(request.precompile_address) {
    let executor_public_key = { registry.get_executor(&request.executor).filter(|info| info.is_active).map(|info| info.public_key.clone()) };
    match executor_public_key {
        Some(public_key) => self.verify_signature_direct(&public_key, request).await?,
        None => return Err(VerificationError::InvalidRequest("Executor not registered".to_string()))
    }
} else { self.client.verify_single(request).await? }
